from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about astronauts (or related entities) into a
    fluent English sentence.  The function groups triples by their subject and
    builds a clause for each predicate, then joins the clauses into a single
    (or a few) readable sentences.
    """
    if not triples:
        return ""

    # Helper to turn a predicate/object pair into a phrase
    def phrase(subj: str, pred: str, obj: str) -> str:
        """Return a natural‑language phrase for a single predicate."""
        # Strip surrounding quotes and whitespace
        obj = obj.strip().strip('"')
        # Normalise predicate for lookup
        p = pred.lower().replace(" ", "")
        # Helper to format ISO dates nicely
        def fmt_date(d: str) -> str:
            try:
                from datetime import datetime
                dt = datetime.strptime(d, "%Y-%m-%d")
                return dt.strftime("%B %-d, %Y")
            except Exception:
                return d

        # Mapping of predicates to phrase templates
        if p == "birthdate":
            return f"{subj} was born on {fmt_date(obj)}"
        if p == "birthplace":
            return f"{subj} was born in {obj}"
        if p == "deathdate":
            return f"{subj} died on {fmt_date(obj)}"
        if p == "deathplace":
            return f"{subj} died in {obj}"
        if p == "nationality":
            # Express nationality in a deterministic way that matches reference style
            # e.g. "Buzz Aldrin's nationality is United States."
            # For United States we also add the demonym for fluency.
            if obj == "United States":
                return f"{subj}'s nationality is United States"
            elif obj == "United Kingdom":
                return f"{subj}'s nationality is United Kingdom"
            else:
                return f"{subj}'s nationality is {obj}"
        if p == "occupation":
            return f"{subj} was a {obj}"
        if p == "status":
            # Use natural phrasing and lower‑case status values
            low = obj.lower()
            if low == "retired":
                return f"{subj} is retired"
            elif low == "active":
                return f"{subj} is active"
            else:
                return f"{subj} has status {obj}"
        if p == "selectedbynasa":
            return f"{subj} was selected by NASA in {obj}"
        if p == "mission":
            # Assume subject is an astronaut; use a natural phrasing
            return f"{subj} served on the crew of {obj}"
        if p == "timeinspace":
            # Convert minutes to hours/minutes if possible
            try:
                mins = float(obj)
                hrs = int(mins // 60)
                rem = int(mins % 60)
                if hrs:
                    return f"{subj} spent {hrs} hour{'s' if hrs>1 else ''}" + (f" and {rem} minute{'s' if rem!=1 else ''}" if rem else "") + " in space"
                else:
                    return f"{subj} spent {rem} minute{'s' if rem!=1 else ''} in space"
            except Exception:
                return f"{subj} spent {obj} minutes in space"
        if p == "title":
            return f"{subj} held the title of {obj}"
        if p == "award":
            return f"{subj} received the {obj}"
        if p == "awards":
            return f"{subj} received {obj} awards"
        if p == "ribbonaward":
            return f"{subj} was awarded the {obj}"
        if p == "operator":
            # Prefer a concise active description
            # If the object is NASA, use "NASA‑operated"
            if obj.upper() == "NASA":
                article = "The " if not subj.lower().startswith(("the ", "a ")) else ""
                return f"{article}{subj} was a NASA‑operated mission"
            else:
                article = "The " if not subj.lower().startswith(("the ", "a ")) else ""
                return f"{article}{subj} was operated by {obj}"
        if p == "commander":
            return f"{obj} was the commander of {subj}"
        if p == "backuppilot":
            # Use a natural clause linking the mission and its backup pilot
            return f"{obj} served as the backup pilot for {subj}"
        if p == "crewmembers":
            # Use a natural clause linking the person and the mission
            return f"{obj} was a crew member of {subj}"
        if p == "alternativename":
            return f"{subj} is also known as {obj}"
        if p == "servedaschiefoftheastronautofficein":
            return f"{subj} served as Chief of the Astronaut Office in {obj}"
        if p == "representative":
            return f"{obj} was the representative of {subj}"
        if p == "bird":
            return f"The {obj} is the state bird of {subj}"
        if p == "partstype":
            return f"{subj} has parts type {obj}"
        # Generic fallback
        return f"{subj} {pred} {obj}"

    # Build phrases for all triples in the original order and combine them into one sentence.
    # For subjects that appear multiple times, concatenate their clauses with "and"
    # to produce a smoother single sentence.
    phrases_by_subj = {}
    for t in triples:
        phr = phrase(t.subject, t.predicate, t.object)
        phrases_by_subj.setdefault(t.subject, []).append(phr)
    phrases = []
    for subj, phrs in phrases_by_subj.items():
        if len(phrs) == 1:
            phrases.append(phrs[0])
        else:
            combined = " and ".join(phrs)
            phrases.append(combined)
    if not phrases:
        return ""
    if len(phrases) == 1:
        sentence = phrases[0]
    else:
        # Join main clauses with commas and a final "and"
        sentence = ", ".join(phrases[:-1]) + ", and " + phrases[-1]
    return sentence + "."

# EVOLVE-BLOCK-END

